# Monitoring clip fraction during RLHF training
import wandb

class ClipDiagnostics:
    def __init__(self, target_clip_frac: float = 0.1, alert_threshold: float = 0.4):
        self.target_clip_frac = target_clip_frac
        self.alert_threshold = alert_threshold

    def log(self, step: int, stats: dict):
        clip_frac = stats.get("clip_fraction", 0)
        approx_kl = stats.get("approx_kl", 0)

        wandb.log({
            "clip_fraction": clip_frac,
            "approx_kl": approx_kl,
            "ratio_mean": stats.get("ratio_mean", 1.0),
        }, step=step)

        if clip_frac > self.alert_threshold:
            print(
                f"[step {step}] WARNING: clip_fraction={clip_frac:.2f} "
                f"— policy updating too fast. Reduce LR or ppo_epochs."
            )
        if approx_kl > 0.1:
            print(
                f"[step {step}] WARNING: approx_kl={approx_kl:.3f} "
                f"— policy diverging. Increase KL coefficient."
            )
